import React from 'react';

const Projects = () => (
  <section
    id="Projects"
    className="min-h-screen flex flex-col items-center py-24"
    style={{ background: '#112240', fontFamily: "'Orbitron', sans-serif" }}
  >
    <h1 className="text-4xl text-white mb-12 font-bold">Projects</h1>

    <div
      className="p-6 rounded-xl"
      style={{ background: '#f8f9fa', borderLeft: '5px solid #0d6efd' }}
    >
      <p style={{ color: '#0b1f3a' }}>Your projects here</p>
    </div>
  </section>
);

export default Projects;
